---@class LActivityWebData
local LActivityWebData = LxClass("LActivityWebData", nil)
------------------------------------------------------------------
function LActivityWebData:LActivityWebData()
	self._sid = nil --活动id

	self._status = 0 --当前状态

	self._verTimestamp = "" --当前版本时间戳

	self._curLng = ""

	self._webData = nil
	self._pageMap = nil
	self._entryMap = nil

	self._retryCount = 0

	self._retryDelayTimer = nil
end

function LActivityWebData:IsDestroy()
	return self._isDestroy
end

function LActivityWebData:InitFirstData(sid, verifyTime)
	self._sid = sid
	self._verTimestamp = verifyTime
end

function LActivityWebData:Destroy()
	if self._isDestroy then return end

	self:StopRetryDelayTimer()

	table.removeall(self)
	self._isDestroy = true
end

function LActivityWebData:GetData()
	return self._webData
end

function LActivityWebData:GetPage(pageId)

	if not self._webData then
		return
	end

	if not self._pageMap then
		self._pageMap = {}

		local chunks = self._webData.chunk or {}
		for k,v in ipairs(chunks) do
			local pageId = v.id
			self._pageMap[pageId] = v
		end
	end

	return self._pageMap[pageId]

end

function LActivityWebData:GetEntry(pageId,entryId)
	if not self._webData then
		return
	end

	local page = self:GetPage(pageId)
	if not page then
		return
	end

	if not self._entryMap then
		self._entryMap = {}
	end

	local entryMap = self._entryMap[pageId]
	if not entryMap then
		entryMap = {}
		self._entryMap[pageId] = entryMap

		for k,v in ipairs(page.entries) do
			entryMap[v.id] = v
		end
	end

	return entryMap[entryId]

end

function LActivityWebData:SetVerifyTime(time)
	self._verTimestamp = time
end

function LActivityWebData:StopRetryDelayTimer()
	if self._retryDelayTimer then
		LxTimer.DelayTimeStop(self._retryDelayTimer)
		self._retryDelayTimer = nil
	end
end

function LActivityWebData:IsOutOfDate(verifyTime)
	return self._verTimestamp ~= verifyTime
end

function LActivityWebData:StartInitWebData()
	local lng = gLGameLanguage:GetLanguageFlag()
	self._curLng = lng

	self:StopRetryDelayTimer()
	self._retryCount = 0
	self._status = 0
	self._webData = nil
	self._pageMap = nil
	self._entryMap = nil

	if self:TryLoadFromFile() then
		return true
	end

	self:TryLoadFromWeb()
end

function LActivityWebData:TryLoadFromFile()
	local ver = self._verTimestamp
	local lng = self._curLng
	local documentPath = self:GetFilePath(ver, lng)
	local str = LFileHelper.ReadAllTextFromCache(documentPath)
	local resultTbl
	if not string.isempty(str) then
		resultTbl = JSON.decode(str)
	end
	if(resultTbl) then
		if resultTbl.verifyTime == ver then
			self._webData = resultTbl
			return true
		end
	end
	return false
end

function LActivityWebData:TryLoadFromWeb()
	local ver = self._verTimestamp
	local lng = self._curLng

	local webUrl = gLGameLogin:GetActivityUrl()
	if string.isempty(webUrl) then
		printErrorN("activity url is nil")
		return
	end
	local urlSuffix
	if lng ~= "zhtw" then
		urlSuffix = string.format("%s_%s_%s.json",self._sid,lng,ver)
	else
		urlSuffix = string.format("%s_%s.json",self._sid,ver)
	end
	local urlList = {webUrl}

	self._isReqing = true
	LxHttpHelper.DoWebRequestURL(nil,urlList, urlSuffix,function (...) self:OnActivityWebDataResult(ver, lng,...) end, false)
end

function LActivityWebData:GetFilePath(ver, lng)
	local path = string.format("%sactivityweb/%s_%s.json",CS.AppPersistentDataPath(),self._sid,lng)
	--local path = CS.AppPersistentDataPath() .."activityweb/"..tostring(self._sid).."_"..tostring(lng)..".json"
	return path
end

function LActivityWebData:OnActivityWebDataResult(ver, lng, ret, result,url, progress, bytes)
	if self._isDestroy then
		return
	end
	if ver ~= self._verTimestamp then return end
	if lng ~= self._curLng then return end

	self._isReqing = false

	if ret == CS.YXWebRet.ok then
		self._status = 1
		if not string.isempty(result) then
			local resultTbl = JSON.decode(result)

			self._webData = resultTbl
			FireEvent(EventNames.ON_ACTIVITY_CONFIG_DATA,self._webData,self._sid)
			if not resultTbl then return end
			resultTbl.verifyTime = ver

			result = JSON.encode(resultTbl)
			local documentPath = self:GetFilePath(ver, lng)
			LFileHelper.WriteAllTextToCache(documentPath, result)

		end
	elseif ret == CS.YXWebRet.Loading then

	else
		self._status = -1
		self:RetryLoaded()
	end
end

function LActivityWebData:IsReqing()
	return self._isReqing or false
end

function LActivityWebData:RetryLoaded()
	self._retryCount = self._retryCount+1
	if self._retryCount > 3 then
		self._status = -2
		return
	end
	self:StopRetryDelayTimer()
	self._retryDelayTimer = LxTimer.DelayTimeCall(function ()
		self:TryLoadFromWeb()
	end, 5)
end

return LActivityWebData